(function(){
  var questions = [{"type":"mcq","html":"The <span class=\"code-func\">input()</span> function asks the user to type something. Unless you convert it, Python stores what the user typed as text:<br><span class=\"green-keyword\">name</span> = <span class=\"code-func\">input</span>(<span class=\"code-string\">\"Enter name\"</span>)<br>What does this line store?","correct":"Stores text input","options":["Stores text input","Stores number input","Prints a message"],"right":"input() returns text.","wrong":"input() returns a string unless it is converted."},{"type":"text","html":"Write one line of code to ask the user for a <span class=\"green-keyword\">city</span> and store what they type in a variable called <span class=\"green-keyword\">city</span>. Use <span class=\"code-func\">input()</span> with a prompt inside quote marks.","correct":"city = input(\"Enter city\")","pattern":"^\\s*city\\s*=\\s*input\\s*\\(\\s*[\"'][^\"']+[\"']\\s*\\)\\s*$","right":"Assign input() to a variable.","wrong":"Use city = input(\"...\") with a prompt inside the brackets."},{"type":"mcq","html":"The user types text into <span class=\"code-func\">input()</span>. To use that input as a whole number, wrap it in <span class=\"code-func\">int()</span>:<br><span class=\"green-keyword\">age</span> = <span class=\"code-func\">int</span>(<span class=\"code-func\">input</span>(<span class=\"code-string\">\"Enter age\"</span>))<br>What does this line store?","correct":"Stores number input","options":["Stores text input","Stores number input","Creates a comment"],"right":"int() converts the input to a whole number.","wrong":"int(input(...)) is used when the typed input should become a whole number."},{"type":"text","html":"Write one line of code to ask for <span class=\"green-keyword\">score</span> and store it as a whole number. Use <span class=\"code-func\">int</span>(<span class=\"code-func\">input</span>(...)) so the answer is converted from text to an integer.","correct":"score = int(input(\"Enter score\"))","pattern":"^\\s*score\\s*=\\s*int\\s*\\(\\s*input\\s*\\(\\s*[\"'][^\"']+[\"']\\s*\\)\\s*\\)\\s*$","right":"Use int(input(...)) for whole numbers.","wrong":"Wrap input() inside int(), and store it in score."},{"type":"mcq","html":"Data type matters. This value looks like a number, but it is inside quote marks:<br><span class=\"code-string\">\"42\"</span><br>What data type is it?","correct":"String","options":["String","Integer","Float","Boolean"],"right":"Anything in quotes is a string.","wrong":"Quote marks make this text, so the data type is string."},{"type":"text","html":"A decimal number has a fractional part, such as <span class=\"green-keyword\">3.14</span>. What data type name is used for decimal numbers in Python?","correct":"Float","answers":["Float","float"],"right":"Decimal numbers are floats.","wrong":"3.14 is a float."},{"type":"mcq","html":"Before conversion, <span class=\"code-func\">input()</span> always returns the same data type, even if the user types digits. What data type does raw input return?","correct":"String","options":["String","Integer","Float","Boolean"],"right":"input() always returns a string.","wrong":"Convert input with int() or float() if you need a number."},{"type":"text","html":"The variable <span class=\"green-keyword\">height</span> currently stores a value that needs to become a decimal number. Write the conversion expression that turns <span class=\"green-keyword\">height</span> into a float.","correct":"float(height)","pattern":"^\\s*float\\s*\\(\\s*height\\s*\\)\\s*$","right":"float() converts to a decimal number.","wrong":"Use float(height)."},{"type":"mcq","html":"This code asks the user for their favourite food, stores it, then prints a message with the stored value:<br><span class=\"green-keyword\">food</span> = <span class=\"code-func\">input</span>(<span class=\"code-string\">\"Food?\"</span>)<br><span class=\"code-func\">print</span>(<span class=\"code-string\">\"I like\"</span>, <span class=\"green-keyword\">food</span>)<br>What does the whole code do?","correct":"Asks for food then prints it with a message","options":["Asks for food then prints it with a message","Converts food to a number","Prints the word food only"],"right":"The variable is printed with a message.","wrong":"The input is stored in food, then printed with text."},{"type":"text","html":"The variable <span class=\"green-keyword\">age</span> needs to be treated as a whole number. Write the conversion expression that converts <span class=\"green-keyword\">age</span> to an integer.","correct":"int(age)","pattern":"^\\s*int\\s*\\(\\s*age\\s*\\)\\s*$","right":"int() converts a value to an integer.","wrong":"Use int(age)."}];
  var helpSlides = [{"title":"How input() works","body":"<p><code class=\"bg-gray-100 px-1 rounded\">input()</code> asks the user to type something. The prompt goes inside the brackets, usually as a string: <code>name = input(\"Enter name\")</code>.</p><p class=\"mt-2\">The value the user types is stored in the variable on the left.</p>"},{"title":"Input starts as text","body":"<p>Raw <code>input()</code> always returns a string. That means even if the user types <code>42</code>, Python receives it as text first.</p><p class=\"mt-2\">Use plain <code>input()</code> for names, cities, hobbies, and other text.</p>"},{"title":"Converting numbers","body":"<p>Use <code>int(input(\"...\"))</code> when the user should type a whole number, such as age or score.</p><p class=\"mt-2\">Use <code>float(value)</code> for decimal numbers such as height or money. Use <code>int(value)</code> for whole numbers.</p>"},{"title":"Data types","body":"<p><strong>String</strong>: text, usually in quotes, like <code>\"42\"</code>. <strong>Integer</strong>: whole number, like <code>42</code>. <strong>Float</strong>: decimal number, like <code>3.14</code>. <strong>Boolean</strong>: <code>True</code> or <code>False</code>.</p>"}];
  var idx=0, score=0, answered=false, results=[];
  var modal=document.getElementById('selection-dna-help-modal');
  var helpTitle=document.getElementById('selection-dna-help-title');
  var helpBody=document.getElementById('selection-dna-help-body');
  var helpPager=document.getElementById('selection-dna-help-pager');
  var helpPrev=document.getElementById('selection-dna-help-prev');
  var helpNext=document.getElementById('selection-dna-help-next');
  var helpIdx=0;
  function renderSlide(){
    var slide=helpSlides[helpIdx];
    helpTitle.textContent=slide.title;
    helpBody.innerHTML=slide.body;
    helpPager.textContent=(helpIdx+1)+' / '+helpSlides.length;
    helpPrev.disabled=helpIdx===0;
    helpNext.textContent=helpIdx===helpSlides.length-1?'Close':'Next';
  }
  document.getElementById('selection-dna-help-btn').onclick=function(){ helpIdx=0; renderSlide(); modal.classList.remove('hidden'); };
  document.getElementById('selection-dna-help-close').onclick=function(){ modal.classList.add('hidden'); };
  helpPrev.onclick=function(){ if(helpIdx>0){ helpIdx--; renderSlide(); } };
  helpNext.onclick=function(){ if(helpIdx<helpSlides.length-1){ helpIdx++; renderSlide(); } else { modal.classList.add('hidden'); } };
  modal.addEventListener('click', function(e){ if(e.target===modal) modal.classList.add('hidden'); });

  var qEl=document.getElementById('selection-dna-q');
  var optEl=document.getElementById('selection-dna-opts');
  var ansWrap=document.getElementById('selection-dna-answer-wrap');
  var fbEl=document.getElementById('selection-dna-fb');
  var progEl=document.getElementById('selection-dna-prog');
  var scoreEl=document.getElementById('selection-dna-score');

  function normalize(s){ return String(s).trim().replace(/[??]/g,'"').replace(/[??]/g,"'"); }
  function esc(str){ return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  function checkText(q, raw){
    var val=normalize(raw);
    if(q.pattern) return new RegExp(q.pattern,'i').test(val);
    if(q.answers) return q.answers.some(function(a){ return normalize(a).toLowerCase()===val.toLowerCase(); });
    return normalize(q.correct).toLowerCase()===val.toLowerCase();
  }
  function show(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx]; answered=false;
    progEl.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML='<span class="ex-code">'+q.html+'</span>';
    optEl.innerHTML=''; ansWrap.innerHTML=''; fbEl.textContent=''; fbEl.className='ex-feedback';
    if(q.type==='text') renderText(q); else renderMcq(q);
  }
  function renderMcq(q){
    q.options.forEach(function(o){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o;
      btn.onclick=function(){
        if(answered) return; answered=true;
        optEl.querySelectorAll('.ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); });
        var ok=o===q.correct;
        results.push({q:q, wasCorrect:ok, chosen:o});
        if(ok){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
        else { btn.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. The answer is: '+q.correct; setTimeout(function(){ idx++; show(); }, 1800); }
      };
      optEl.appendChild(btn);
    });
  }
  function renderText(q){
    ansWrap.innerHTML='<input id="selection-dna-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your answer here"/><button id="selection-dna-check" class="ex-btn" style="margin-top:8px">Check</button>';
    var input=document.getElementById('selection-dna-answer');
    var btn=document.getElementById('selection-dna-check');
    function submit(){
      if(answered) return;
      var val=input.value;
      if(!val.trim()){ fbEl.className='ex-feedback hint'; fbEl.textContent='Type your answer first.'; return; }
      answered=true;
      input.disabled=true; btn.disabled=true;
      var ok=checkText(q,val);
      results.push({q:q, wasCorrect:ok, chosen:val});
      if(ok){ input.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
      else { input.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. Expected: '+q.correct; setTimeout(function(){ idx++; show(); }, 2200); }
    }
    btn.onclick=submit;
    input.onkeydown=function(e){ if(e.key==='Enter') submit(); };
    input.focus();
  }
  function finish(){
    var pct=Math.round(score/questions.length*100);
    qEl.innerHTML=''; optEl.innerHTML=''; ansWrap.innerHTML=''; fbEl.textContent=''; progEl.textContent='Complete'; scoreEl.textContent='';
    var resultsEl=document.getElementById('selection-dna-results'); resultsEl.classList.remove('hidden');
    var msg=pct===100?'Full marks. You are ready to build on last lesson.':pct>=70?'Good work overall. Review anything you missed below.':'A few areas to revisit before moving on.';
    var html='<div class="ex-box"><p style="font-family:sans-serif;font-size:0.95rem;font-weight:600;color:#cdd6f4;margin-bottom:4px">'+score+'/'+questions.length+' - '+pct+'%</p><p style="font-family:sans-serif;font-size:0.85rem;color:#a6adc8;margin-bottom:16px">'+msg+'</p>';
    results.forEach(function(r){
      html+='<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px;padding:8px 10px;background:'+(r.wasCorrect?'#1a2f20':'#2a1a1a')+';border:1px solid '+(r.wasCorrect?'#2d4a35':'#4a2a2a')+';border-radius:6px">';
      html+='<span style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+';font-size:1rem;flex-shrink:0;margin-top:1px">'+(r.wasCorrect?'&#10003;':'&#10007;')+'</span>';
      html+='<div><div class="ex-code" style="font-size:0.82rem;margin-bottom:3px">'+r.q.html+'</div>';
      html+='<p style="font-family:sans-serif;font-size:0.78rem;color:#a6adc8;margin:0 0 3px 0">Your answer: <strong style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+'">'+esc(r.chosen)+'</strong> - expected: <strong style="color:#a6e3a1">'+esc(r.q.correct)+'</strong></p>';
      html+='<p style="font-family:sans-serif;font-size:0.8rem;color:#bac2de;margin:0">'+(r.wasCorrect?r.q.right:(r.q.wrong||r.q.right))+'</p></div></div>';
    });
    html+='</div>'; resultsEl.innerHTML=html;
    window.__markStepComplete && window.__markStepComplete();
  }
  show();
})();

