  function render(){ if(idx>=examData.length){ finish(); return; } var q=examData[idx]; prog.textContent='Question '+(idx+1)+' of '+examData.length; scoreEl.textContent='Score: '+score; if(q.type==='mcq') renderMcq(q); else renderText(q); }
  function renderMcq(q){
    var html='<div class="ex-box"><div class="ex-prompt" style="color:#89b4fa;font-family:sans-serif;font-size:0.85rem;margin-bottom:6px">'+q.prompt+'</div>';
    if(q.codeHtml) html+='<div class="ex-code" style="margin-bottom:10px">'+q.codeHtml+'</div>';
    html+='<div class="ex-options" id="s4-opts"></div><div class="ex-feedback" id="s4-fb"></div><div class="ex-explanation" id="s4-exp" style="display:none"></div></div>'; wrap.innerHTML=html;
    q.options.slice().sort(function(){return Math.random()-0.5;}).forEach(function(opt){ var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=opt; btn.onclick=function(){ document.querySelectorAll('#s4-opts .ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); }); var fb=document.getElementById('s4-fb'), exp=document.getElementById('s4-exp'); exp.textContent=q.explanation||''; exp.style.display=exp.textContent?'block':'none'; if(opt===q.correct){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){idx++;render();},1000); } else { btn.classList.add('wrong'); fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is shown in green.'; setTimeout(function(){idx++;render();},2200); } }; document.getElementById('s4-opts').appendChild(btn); });
  }
  function renderText(q){
    var rows=q.type==='extended_run'?10:2;
    var html='<div class="ex-box"><div class="ex-prompt" style="color:#89b4fa;font-family:sans-serif;font-size:0.85rem;margin-bottom:8px">'+String(q.prompt).replace(/\\n/g,'<br>')+'</div>';
    html+='<textarea id="s4-ta" class="ex-textarea" rows="'+rows+'" spellcheck="false" placeholder="Write your answer here"></textarea><button id="s4-check" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback" id="s4-fb"></div><div class="ex-explanation" id="s4-exp" style="display:none">'+(q.explanation||'')+'</div></div>'; wrap.innerHTML=html;
    document.getElementById('s4-check').onclick=function(){ checkText(q); }; document.getElementById('s4-ta').focus();
  }
  function checkText(q){
    var code=document.getElementById('s4-ta').value.trim(); var fb=document.getElementById('s4-fb'), exp=document.getElementById('s4-exp'); exp.style.display='block';
    if(!code){ fb.className='ex-feedback hint'; fb.textContent='Write your answer first.'; return; }
    var ok=false;
    if(q.type==='text_simple') ok=q.useRegex ? rx(q.correctCode, code) : code===q.correctCode;
    else if(q.type==='extended_run') ok=new RegExp('^\\s*score\\s*=\\s*\\d+','im').test(code) && new RegExp('^\\s*age\\s*=\\s*\\d+','im').test(code) && new RegExp('if\\s+score\\s*>=\\s*50\\s*:\\s*[\\r\\n]+\\s+print\\s*\\([^)]*Passed[^)]*\\)','im').test(code) && new RegExp('if\\s+age\\s*>=\\s*18\\s*:\\s*[\\r\\n]+\\s+print\\s*\\([^)]*Adult[^)]*\\)','im').test(code);
    if(ok){ score++; scoreEl.textContent='Score: '+score; fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){idx++;render();},1200); } else { fb.className='ex-feedback err'; fb.textContent='Not quite. Use the scaffold shown below.'; }
  }
  function finish(){ var pct=Math.round(score/examData.length*100); var grade=pct>=90?'Outstanding':pct>=70?'Secure':pct>=50?'Developing':'Needs more practice'; wrap.innerHTML='<div class="ex-box"><p style="font-family:sans-serif;font-size:1rem;font-weight:600;color:#cdd6f4;margin-bottom:6px">Stage 4 complete: '+score+'/'+examData.length+' ('+pct+'%)</p><p style="font-family:sans-serif;font-size:0.9rem;color:#a6adc8;margin-bottom:10px">Grade: '+grade+'</p><p style="font-family:sans-serif;font-size:0.85rem;color:#bac2de">You have practised comparison operators, if statements, and logical operators.</p></div>'; prog.textContent='Complete'; scoreEl.textContent=''; window.__markStepComplete && window.__markStepComplete(); }
  render();
})();

steps.css:
.ex-box{background:#1e1e2e;border:1px solid #313244;border-radius:10px;padding:16px 20px;margin-bottom:14px}
.ex-prompt{font-family:sans-serif;font-size:0.85rem;color:#cdd6f4;margin-bottom:10px}
.ex-code{color:#cdd6f4;font-size:0.95rem;line-height:1.7;letter-spacing:0.01em;font-family:'Courier New',monospace;display:block}
.code-func{color:#cba6f7}
.code-string{color:#a6e3a1}
.code-comment{color:#94e2d5;font-style:italic}
.code-error{color:#f38ba8}
.green-keyword{color:#a6e3a1;font-weight:600}
.ex-options{display:block;margin-top:10px}
.ex-opt{display:block;width:100%;background:#313244;color:#cdd6f4;border:1px solid #45475a;border-radius:6px;padding:10px 14px;font-family:'Courier New',monospace;font-size:0.9rem;cursor:pointer;text-align:left;margin-bottom:6px;box-sizing:border-box;line-height:1.4}
.ex-opt:last-child{margin-bottom:0}
.ex-opt:hover:not([disabled]){background:#45475a;border-color:#94e2d5}
.ex-opt.correct{background:#1a3328!important;border-color:#a6e3a1!important;color:#a6e3a1!important}
.ex-opt.wrong{background:#351c1c!important;border-color:#f38ba8!important;color:#f38ba8!important}
.ex-opt[disabled]{cursor:default}
.ex-feedback{margin-top:10px;font-size:0.85rem;min-height:20px;font-family:sans-serif;line-height:1.4}
.ex-feedback.ok{color:#a6e3a1}
.ex-feedback.err{color:#f38ba8}
.ex-feedback.hint{color:#f9e2af}
.ex-progress{font-size:0.8rem;color:#585b70;margin-bottom:4px;font-family:sans-serif}
.ex-score{font-size:0.85rem;font-weight:600;color:#cba6f7;margin-bottom:10px;font-family:sans-serif}
.ex-label{font-family:sans-serif;font-size:0.82rem;color:#89b4fa;margin-bottom:10px;display:block}
.ex-explanation{background:#252535;border-left:3px solid #89b4fa;padding:8px 12px;margin-top:10px;font-size:0.82rem;color:#bac2de;font-family:sans-serif;border-radius:0 6px 6px 0;line-height:1.5}

.ex-input,.ex-textarea{width:100%;background:#11111b;color:#cdd6f4;border:1px solid #45475a;border-radius:6px;padding:10px 12px;font-family:'Courier New',monospace;font-size:0.9rem;box-sizing:border-box;line-height:1.45}
.ex-input:focus,.ex-textarea:focus{outline:none;border-color:#89b4fa;box-shadow:0 0 0 2px rgba(137,180,250,0.25)}
.ex-input.correct,.ex-textarea.correct{border-color:#a6e3a1;background:#14251d}
.ex-input.wrong,.ex-textarea.wrong{border-color:#f38ba8;background:#281616}
.ex-btn{display:inline-block;background:#2563eb;color:white;border:0;border-radius:6px;padding:8px 14px;font-family:sans-serif;font-size:0.85rem;font-weight:600;cursor:pointer}
.ex-btn:hover:not([disabled]){background:#1d4ed8}
.ex-btn[disabled]{opacity:0.55;cursor:default}

