(function(){
  var mcqPool = [{"prompt":"Choose the comparison operator:","html":"<span style=\"font-size:0.9rem\">Greater than or equal to</span>","correct":">=","options":[">=",">","<=","=>"]},{"prompt":"Choose the comparison operator:","html":"<span style=\"font-size:0.9rem\">Not equal to</span>","correct":"!=","options":["!=","==","<>","not="]},{"prompt":"Choose the logical operator:","html":"<span style=\"font-size:0.9rem\">Both sides must be True</span>","correct":"and","options":["and","or","not","&&"]},{"prompt":"Choose the full if block:","html":"<span style=\"font-size:0.9rem\">Check if score is at least 50, then print a message.</span>","correct":"if score >= 50:\n    print('Passed!')","options":["if score >= 50:\n    print('Passed!')","if score => 50:\n    print('Passed!')","if score >= 50\n    print('Passed!')","if score >= 50;\n    print('Passed!')"]}];
  var textPool = [{"label":"Type the operator:","html":"<span style=\"font-size:0.9rem\">Less than or equal to</span>","pattern":"^\\s*<=\\s*$","hint":"<="},{"label":"Type the operator:","html":"<span style=\"font-size:0.9rem\">Equal to</span>","pattern":"^\\s*==\\s*$","hint":"=="},{"label":"Type the logical operator:","html":"<span style=\"font-size:0.9rem\">Either side can be True</span>","pattern":"^\\s*or\\s*$","hint":"or"},{"label":"Type the full if block:","html":"<span style=\"font-size:0.9rem\">Check if lives does not equal 0, then print a message.</span>","pattern":"^\\s*if\\s+lives\\s*!=\\s*0\\s*:\\s*\\n\\s+print\\s*\\(\\s*[\"'][^\"']+[\"']\\s*\\)\\s*$","hint":"if lives != 0:\n    print(\"Keep playing\")","multiline":true}];
  var streak=0, best=parseInt(localStorage.getItem('pylearn_selection_best')||'0',10); document.getElementById('sel-ep-best').textContent=best;
  function rand(a){ return a[Math.floor(Math.random()*a.length)]; }
  function correct(){ streak++; if(streak>best){ best=streak; localStorage.setItem('pylearn_selection_best', best); document.getElementById('sel-ep-best').textContent=best; } document.getElementById('sel-ep-streak').textContent=streak; if(streak>=5)window.__markStepComplete&&window.__markStepComplete(); }
  function wrong(){ streak=0; document.getElementById('sel-ep-streak').textContent=streak; }
  function next(){ Math.random()<0.5 ? showMcq(rand(mcqPool)) : showText(rand(textPool)); }
  function showMcq(q){ var wrap=document.getElementById('sel-ep-q'); wrap.innerHTML='<div class="ex-prompt">'+q.prompt+'</div><div class="ex-code" style="margin-bottom:10px">'+q.html+'</div><div class="ex-options" id="sel-ep-opts"></div><div class="ex-feedback" id="sel-ep-fb"></div>'; q.options.slice().sort(function(){return Math.random()-0.5;}).forEach(function(o){ var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o; btn.onclick=function(){ document.querySelectorAll('#sel-ep-opts .ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct)b.classList.add('correct'); }); var fb=document.getElementById('sel-ep-fb'); if(o===q.correct){ btn.classList.add('correct'); correct(); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(next,1000); } else { btn.classList.add('wrong'); wrong(); fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is shown in green.'; } }; document.getElementById('sel-ep-opts').appendChild(btn); }); }
  function showText(q){ var wrap=document.getElementById('sel-ep-q'); wrap.innerHTML='<div class="ex-prompt">'+q.label+'</div><div class="ex-code" style="margin-bottom:10px">'+q.html+'</div>'+(q.multiline?'<textarea id="sel-ep-answer" class="ex-textarea" rows="3" spellcheck="false" placeholder="if condition:\\n    print(\"Message\")"></textarea>':'<input id="sel-ep-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your answer here"/>')+'<button id="sel-ep-check" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback" id="sel-ep-fb"></div><div class="ex-explanation" id="sel-ep-hint" style="display:none"></div>'; document.getElementById('sel-ep-check').onclick=function(){ var input=document.getElementById('sel-ep-answer'); var val=input.value.trim(); var fb=document.getElementById('sel-ep-fb'); var hint=document.getElementById('sel-ep-hint'); if(!val){ fb.className='ex-feedback hint'; fb.textContent='Type your answer first.'; hint.textContent=q.hint; hint.style.display='block'; return; } if(new RegExp(q.pattern,'i').test(val)){ input.classList.add('correct'); correct(); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(next,1000); } else { input.classList.add('wrong'); wrong(); fb.className='ex-feedback err'; fb.textContent='Not quite. Check the syntax.'; hint.textContent=q.hint; hint.style.display='block'; } }; document.getElementById('sel-ep-answer').onkeydown=function(e){ if(e.key==='Enter' && !q.multiline) document.getElementById('sel-ep-check').click(); if(e.key==='Enter' && e.ctrlKey) document.getElementById('sel-ep-check').click(); }; document.getElementById('sel-ep-answer').focus(); }
  next();
})();

